consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
.fade {
  position: absolute;
  pointer-events: none;
  z-index: 10;
  transform: translateZ(0);
  backface-visibility: hidden;
}

@media (prefers-reduced-motion: reduce) {
  .fade { transition: none; }
}

.fadeTop {
  top: 0; left: 0; right: 0;
  background: linear-gradient(to bottom, var(--background) 0%, var(--background) 50%, transparent 100%);
}

.fadeBottom {
  bottom: 0; left: 0; right: 0;
  background: linear-gradient(to top, var(--background) 0%, transparent 100%);
}

.fadeLeft {
  top: 0; bottom: 0; left: 0;
  background: linear-gradient(to right, var(--background) 0%, transparent 100%);
}

.fadeRight {
  top: 0; bottom: 0; right: 0;
  background: linear-gradient(to left, var(--background) 0%, transparent 100%);
}

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import styles from './Fade.module.css';

export type FadeSide = 'top' | 'bottom' | 'left' | 'right';

export interface FadeProps {
  side: FadeSide;
  height: string;
  background?: string;
  className?: string;
  style?: React.CSSProperties;
}

const sideClassMap: Record<FadeSide, string> = {
  top: 'fadeTop',
  bottom: 'fadeBottom',
  left: 'fadeLeft',
  right: 'fadeRight',
};

export const Fade = forwardRef<HTMLDivElement, FadeProps>(
  ({ side, height, background = 'var(--color-background-secondary)', className, style = {} }, ref) => (
    <div
      ref={ref}
      className={cn(styles.fade, styles[sideClassMap[side]], className)}
      style={{ ...style, height, '--background': background } as React.CSSProperties}
      aria-hidden="true"
    />
  )
);

Fade.displayName = 'Fade';
